require 'spikard'
require 'json'
require 'faraday'

RSpec.describe 'body_limits' do
  let(:base_url) { ENV.fetch('TEST_SERVER_URL', 'http://localhost:8080') }
  let(:client) do
    Faraday.new(url: base_url) do |f|
      f.request :json
      f.response :json, content_type: /\bjson$/
    end
  end

  describe 'POST /body-limit/over' do
    it 'Requests that exceed the configured max body size should be rejected with Payload Too Large.' do
      response = client.post('/body-limit/over',
        json: { 'note' => 'xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx' }
      )
      expect(response.status).to eq(413)
    end
  end

  describe 'POST /body-limit/under' do
    it 'Ensures requests smaller than the configured body limit are accepted.' do
      response = client.post('/body-limit/under',
        json: { 'note' => 'small' }
      )
      expect(response.status).to eq(200)
      expect(response.body).to eq({ 'accepted' => true, 'note' => 'small' })
    end
  end
end
